import { create } from 'zustand';

const useUserStore = create((set) => ({
  user: null,
  isAuthenticated: false,

  setUser: (user) => {
    set({ user, isAuthenticated: !!user });
  },

  logout: () => {
    set({ user: null, isAuthenticated: false });
  }
}));

export { useUserStore };
